// Helper function to get full address string
const getFullAddress = (donation: PublicDonation): string => {
  const address = donation.addresses?.[0];
  if (!address) return "No address provided";

  const parts = [
    address.line1,
    address.line2,
    address.city,
    address.region,
    address.postalCode,
    address.country,
  ].filter(Boolean);

  return parts.join(", ");
};

